import akka.http.scaladsl.Http
import akka.http.scaladsl.model._
import akka.http.scaladsl.server.Directives._
import akka.actor.ActorSystem
import akka.stream.ActorMaterializer
import scala.xml.XML

object ConfigService {
  implicit val system = ActorSystem("config-service")
  implicit val materializer = ActorMaterializer()
  implicit val executionContext = system.dispatcher

  def main(args: Array[String]): Unit = {
    val route =
      path("parse-config") {
        post {
          entity(as[String]) { xmlString =>
            try {
              val xml = XML.loadString(xmlString)
              val settings = extractSettings(xml)
              complete(HttpResponse(StatusCodes.OK, entity = settings.toString()))
            } catch {
              case e: Exception =>
                complete(HttpResponse(StatusCodes.BadRequest, entity = s"Invalid XML: ${e.getMessage}"))
            }
          }
        }
      }

    Http().bindAndHandle(route, "localhost", 8080)
    println("Server online at http://localhost:8080/parse-config")
  }

  def extractSettings(xml: scala.xml.Elem): Map[String, String] = {
    (xml \\ "setting").map { setting =>
      val key = (setting \ "@key").text
      val value = setting.text.trim
      key -> value
    }.toMap
  }
}